 fn python_mod_f64(lhs: f64, rhs: f64) -> f64 {
-    lhs - (lhs / rhs).floor() * rhs
+    if rhs.is_infinite() {
+        if rhs.is_sign_positive() {
+            if lhs >= 0.0 || lhs.is_nan() {
+                lhs
+            } else {
+                f64::INFINITY
+            }
+        } else if lhs <= 0.0 || lhs.is_nan() {
+            lhs
+        } else {
+            f64::NEG_INFINITY
+        }
+    } else {
+        lhs - (lhs / rhs).floor() * rhs
+    }
 }

